chrome.runtime.onInstalled.addListener(()=>{console.log("Side Panel Extension installée"),chrome.storage.local.get(["links","settings"],e=>{e.links||chrome.storage.local.set({links:[]}),e.settings||chrome.storage.local.set({settings:{theme:"light",autoSave:!0}})})});chrome.runtime.onMessage.addListener((e,t,s)=>{console.log("Message reçu:",e),s({success:!0})});
